import{c as a,Q as i,j as t,m as n}from"./chunks/framework.Bhbi9jCp.js";const c=JSON.parse('{"title":"M3U8、TS、fMP4 与分片","description":"","frontmatter":{},"headers":[],"relativePath":"mediaTechLearning/11-M3U8-TS-fMP4与分片.md","filePath":"mediaTechLearning/11-M3U8-TS-fMP4与分片.md","lastUpdated":1780887690000}'),e={name:"mediaTechLearning/11-M3U8-TS-fMP4与分片.md"};function p(l,s,h,d,r,k){return i(),t("div",null,[...s[0]||(s[0]=[n(`<h1 id="m3u8、ts、fmp4-与分片" tabindex="-1">M3U8、TS、fMP4 与分片 <a class="header-anchor" href="#m3u8、ts、fmp4-与分片" aria-label="Permalink to &quot;M3U8、TS、fMP4 与分片&quot;">​</a></h1><p>HLS 看起来只是一个 <code>.m3u8</code> 加一堆文件,但生产问题大多藏在分片边界、关键帧和缓存策略里。</p><blockquote><p>一句话先记住:<strong>M3U8 是清单,TS / fMP4 是媒体分片,分片边界最好落在关键帧上</strong>。播放器不是下载&quot;一个视频&quot;,而是按清单不断拉小文件。</p></blockquote><hr><h2 id="一、m3u8-是文本清单" tabindex="-1">一、M3U8 是文本清单 <a class="header-anchor" href="#一、m3u8-是文本清单" aria-label="Permalink to &quot;一、M3U8 是文本清单&quot;">​</a></h2><p>点播清单:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>#EXTM3U</span></span>
<span class="line"><span>#EXT-X-VERSION:3</span></span>
<span class="line"><span>#EXT-X-TARGETDURATION:6</span></span>
<span class="line"><span>#EXT-X-MEDIA-SEQUENCE:0</span></span>
<span class="line"><span>#EXTINF:6.000,</span></span>
<span class="line"><span>seg_000.ts</span></span>
<span class="line"><span>#EXTINF:6.000,</span></span>
<span class="line"><span>seg_001.ts</span></span>
<span class="line"><span>#EXT-X-ENDLIST</span></span></code></pre></div><p>关键字段:</p><table tabindex="0"><thead><tr><th>字段</th><th>意思</th></tr></thead><tbody><tr><td><code>EXT-X-TARGETDURATION</code></td><td>最大分片时长上限</td></tr><tr><td><code>EXT-X-MEDIA-SEQUENCE</code></td><td>第一个分片序号</td></tr><tr><td><code>EXTINF</code></td><td>下一个分片时长</td></tr><tr><td><code>EXT-X-ENDLIST</code></td><td>点播结束标记</td></tr></tbody></table><p>直播清单会不断滑动,通常没有 <code>ENDLIST</code>。</p><hr><h2 id="二、ts-分片" tabindex="-1">二、TS 分片 <a class="header-anchor" href="#二、ts-分片" aria-label="Permalink to &quot;二、TS 分片&quot;">​</a></h2><p>老 HLS 常用 MPEG-TS:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>index.m3u8</span></span>
<span class="line"><span>seg_000.ts</span></span>
<span class="line"><span>seg_001.ts</span></span></code></pre></div><p>优点:</p><ul><li>历史兼容性强</li><li>流式友好</li><li>直播生态成熟</li></ul><p>缺点:</p><ul><li>包开销相对大</li><li>Web 现代播放器里不如 fMP4 精细</li></ul><hr><h2 id="三、fmp4-分片" tabindex="-1">三、fMP4 分片 <a class="header-anchor" href="#三、fmp4-分片" aria-label="Permalink to &quot;三、fMP4 分片&quot;">​</a></h2><p>现代 HLS / DASH 常用 fragmented MP4:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>init.mp4</span></span>
<span class="line"><span>seg_000.m4s</span></span>
<span class="line"><span>seg_001.m4s</span></span></code></pre></div><p><code>init.mp4</code> 放初始化信息,<code>.m4s</code> 放媒体片段。fMP4 更适合和 MSE、DASH、低延迟 HLS 等现代链路配合。</p><p>生成示意:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ffmpeg</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> input.mp4</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -c:v</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libx264</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c:a</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> aac</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -hls_segment_type</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> fmp4</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -hls_time</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 6</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -hls_playlist_type</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vod</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -hls_segment_filename</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;hls/seg_%03d.m4s&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  hls/index.m3u8</span></span></code></pre></div><hr><h2 id="四、分片时长怎么选" tabindex="-1">四、分片时长怎么选 <a class="header-anchor" href="#四、分片时长怎么选" aria-label="Permalink to &quot;四、分片时长怎么选&quot;">​</a></h2><table tabindex="0"><thead><tr><th>时长</th><th>影响</th></tr></thead><tbody><tr><td>1-2s</td><td>延迟低,请求多,成本高</td></tr><tr><td>4-6s</td><td>常规点播 / 普通直播折中</td></tr><tr><td>10s+</td><td>请求少,但首屏和切换慢</td></tr></tbody></table><p>点播常用 4-6 秒。普通直播可 2-6 秒。低延迟直播要另讲,不能只把分片切短。</p><hr><h2 id="五、关键帧对齐" tabindex="-1">五、关键帧对齐 <a class="header-anchor" href="#五、关键帧对齐" aria-label="Permalink to &quot;五、关键帧对齐&quot;">​</a></h2><p>分片边界如果不是关键帧,播放器切换清晰度或从某片开始解码时可能失败。</p><p>常见做法:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ffmpeg</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> input.mp4</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -c:v</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libx264</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 180</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -keyint_min</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 180</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sc_threshold</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -hls_time</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 6</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -c:a</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> aac</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  hls/index.m3u8</span></span></code></pre></div><p>30fps、6 秒分片,<code>-g 180</code>。实际生产要按帧率计算。</p><hr><h2 id="六、缓存策略" tabindex="-1">六、缓存策略 <a class="header-anchor" href="#六、缓存策略" aria-label="Permalink to &quot;六、缓存策略&quot;">​</a></h2><p>点播:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>segment: 长缓存</span></span>
<span class="line"><span>playlist: 可长缓存,因为不会变</span></span></code></pre></div><p>直播:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>segment: 可缓存一段时间</span></span>
<span class="line"><span>playlist: 短缓存或不缓存</span></span></code></pre></div><p>直播清单会变,被 CDN 长缓存就是灾难。用户会一直看到旧分片。</p><hr><h2 id="七、踩坑提醒" tabindex="-1">七、踩坑提醒 <a class="header-anchor" href="#七、踩坑提醒" aria-label="Permalink to &quot;七、踩坑提醒&quot;">​</a></h2><ol><li><strong>清单缓存太久</strong>——直播卡在旧内容。</li><li><strong>分片不从关键帧开始</strong>——拖动和切档出问题。</li><li><strong>分片太短</strong>——请求风暴和 CDN 成本上升。</li><li><strong>TS/fMP4 混用不测端</strong>——播放器兼容差异要实测。</li><li><strong>忽略 MIME</strong>——<code>.m3u8</code> 和 <code>.m4s</code> 要正确返回类型。</li></ol><p>下一篇:<code>12-播放器原理与缓冲策略.md</code>。</p>`,46)])])}const g=a(e,[["render",p]]);export{c as __pageData,g as default};
